import React from 'react';

const ControlPanel = ({ onCaseConvert, onWhitespaceCleanup }) => {
    return (
        <div className="control-panel">
            <button onClick={onCaseConvert}>Convert Case</button>
            <button onClick={onWhitespaceCleanup}>Cleanup Whitespace</button>
        </div>
    );
};

export default ControlPanel;
